// Brand configs — fill in actual Shopify store URLs and credential names
const brands = [
  { slug: 'thiocyn',      storeUrl: 'thiocyn.myshopify.com',      credName: 'Shopify — Thiocyn' },
  { slug: 'take-a-shot',  storeUrl: 'take-a-shot.myshopify.com',  credName: 'Shopify — Take A Shot' },
  { slug: 'dr-severin',  storeUrl: 'dr-severin.myshopify.com',   credName: 'Shopify — Dr. Severin' },
  { slug: 'paigh',        storeUrl: 'paigh.myshopify.com',        credName: 'Shopify — Paigh' },
  { slug: 'wristr',       storeUrl: 'wristr.myshopify.com',       credName: 'Shopify — Wristr' },
  { slug: 'timber-john',  storeUrl: 'timber-john.myshopify.com',  credName: 'Shopify — Timber & John' }
];
return brands.map(b => ({ json: b }));

// Aggregate daily metrics from Shopify orders
const brandSlug = $('Brand Config List').first().json.slug;
const orders = $input.first().json.orders || [];

const totalRevenue = orders
  .filter(o => o.financial_status === 'paid')
  .reduce((sum, o) => sum + parseFloat(o.total_price || 0), 0);

const orderCount = orders.filter(o => o.financial_status === 'paid').length;
const refundCount = orders.filter(o => o.financial_status === 'refunded').length;

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    brand_slug: brandSlug,
    date: today,
    revenue: Math.round(totalRevenue * 100) / 100,
    order_count: orderCount,
    refund_count: refundCount,
    source: 'shopify',
    updated_at: new Date().toISOString()
  }
}];

// Log agent action
return [{
  json: {
    agent_name: 'n8n',
    action: 'shopify_daily_sync',
    brand_slug: $('Aggregate Daily Metrics').first().json.brand_slug,
    status: 'success',
    source: 'scheduled',
    output: { revenue: $('Aggregate Daily Metrics').first().json.revenue, orders: $('Aggregate Daily Metrics').first().json.order_count }
  }
}];
